// ─── PHYSICS ─────────────────────────────────────────────────────────────────
function checkSpriteTileCollision(sprite, tileX, tileY, collisions) {
  if (
    sprite.levelX + sprite.spriteWidth  >= tileX &&
    sprite.levelX                        <= tileX + TILE_SIZE &&
    sprite.levelY + sprite.spriteHeight >= tileY &&
    sprite.levelY                        <= tileY + TILE_SIZE
  ) {
    const ix = Math.max(sprite.levelX, tileX);
    const iy = Math.max(sprite.levelY, tileY);
    const iw = Math.min(sprite.levelX + sprite.spriteWidth,  tileX + TILE_SIZE) - ix;
    const ih = Math.min(sprite.levelY + sprite.spriteHeight, tileY + TILE_SIZE) - iy;

    const cx = sprite.levelX + sprite.spriteWidth  / 2;
    const cy = sprite.levelY + sprite.spriteHeight / 2;
    const tx = tileX + TILE_SIZE / 2;
    const ty = tileY + TILE_SIZE / 2;

    if (cx > tx && ih > iw) collisions.left  = true;
    if (cx < tx && ih > iw) collisions.right = true;
    if (cy < ty && iw > ih && iw > 4) { collisions.top = true; collisions.topY = tileY; }
    if (cy > ty && iw > ih && iw > 4)   collisions.bottom = true;
  }
}

function checkSpriteTileCollisions(sprite, level) {
  const collisions = { left: false, right: false, top: false, bottom: false, topY: null };
  const levelWidth  = level[0].length;
  const levelHeight = level.length;
  for (let i = 0; i < levelWidth; i++) {
    for (let j = 0; j < levelHeight; j++) {
      if (level[j][i] !== 0) {
        checkSpriteTileCollision(sprite, i * TILE_SIZE, j * TILE_SIZE, collisions);
      }
    }
  }
  return collisions;
}

function checkBoxOverlap(ax, ay, aw, ah, bx, by, bw, bh) {
  return ax < bx + bw && ax + aw > bx && ay < by + bh && ay + ah > by;
}

// ─── ENEMY ───────────────────────────────────────────────────────────────────
// Projétil de tridente
function createTrident(enemy) {
  return {
    levelX: enemy.levelX + (enemy.direction === 1 ? enemy.width + 4 : -20),
    levelY: enemy.levelY + enemy.height * 0.35,
    vx: enemy.direction * 280,
    vy: 0,
    dir: enemy.direction,
    timer: 0,
    lifetime: 2200,
    width: 20, height: 6,
  };
}

function updateEnemy(enemy, level, dt) {
  if (enemy.state === 'dead') { enemy.deadTimer += dt * 1000; return; }
  if (enemy.state === 'hurt') {
    enemy.hurtTimer += dt * 1000;
    if (enemy.hurtTimer >= ENEMY_HURT_DURATION) { enemy.state = 'patrol'; enemy.hurtTimer = 0; }
    return;
  }

  const col = checkSpriteTileCollisions(
    { levelX: enemy.levelX, levelY: enemy.levelY, spriteWidth: enemy.width, spriteHeight: enemy.height },
    level,
  );
  if (col.top) {
    if (enemy.velocityY >= 0) { enemy.velocityY = 0; enemy.levelY = (col.topY ?? enemy.levelY) - enemy.height; }
  } else {
    enemy.velocityY += 0.5;
  }
  if (col.bottom && enemy.velocityY < 0) enemy.velocityY = 0;
  enemy.levelY += enemy.velocityY;

  const step = enemy.speed * enemy.direction * dt;
  const nextX = enemy.levelX + step;

  // Tritão: acumula cooldown de disparo
  if (enemy.type === 'goblin') {
    if (!enemy.shootCooldown) enemy.shootCooldown = 0;
    enemy.shootCooldown -= dt * 1000;
  }

  if (nextX <= enemy.patrolLeft) {
    enemy.levelX  = enemy.patrolLeft; enemy.direction = 1;
  } else if (nextX + enemy.width >= enemy.patrolRight) {
    enemy.levelX  = enemy.patrolRight - enemy.width; enemy.direction = -1;
  } else {
    const nc = checkSpriteTileCollisions(
      { levelX: nextX, levelY: enemy.levelY, spriteWidth: enemy.width, spriteHeight: enemy.height },
      level,
    );
    if ((enemy.direction === 1 && nc.right) || (enemy.direction === -1 && nc.left)) {
      enemy.direction *= -1;
    } else {
      const gcX   = enemy.direction === 1 ? nextX + enemy.width + 2 : nextX - 2;
      const gcY   = enemy.levelY + enemy.height + 4;
      const tileCol = Math.floor(gcX / TILE_SIZE);
      const tileRow = Math.floor(gcY / TILE_SIZE);
      if (col.top && tileRow >= 0 && tileRow < level.length && tileCol >= 0 && tileCol < level[0].length) {
        if (level[tileRow][tileCol] === 0) enemy.direction *= -1;
        else enemy.levelX = nextX;
      } else {
        enemy.levelX = nextX;
      }
    }
  }
}

function hurtEnemy(enemy, damage) {
  if (enemy.state === 'dead' || enemy.state === 'hurt') return;
  enemy.hp -= damage;
  if (enemy.hp <= 0) { enemy.hp = 0; enemy.state = 'dead'; enemy.deadTimer = 0; }
  else               { enemy.state = 'hurt'; enemy.hurtTimer = 0; }
}

function isEnemyRemovable(enemy) {
  return enemy.state === 'dead' && enemy.deadTimer >= ENEMY_DEAD_DURATION;
}

function drawEnemy(ctx, enemy, scrollX) {
  const rx = enemy.levelX - scrollX;
  const ry = enemy.levelY;
  const { width: w, height: h } = enemy;
  let alpha = 1;
  if (enemy.state === 'dead') alpha = 1 - Math.min(1, enemy.deadTimer / ENEMY_DEAD_DURATION);

  ctx.save();
  ctx.globalAlpha = alpha;
  const isHurt = enemy.state === 'hurt';

  if (enemy.type === 'slime')  drawSlime(ctx, rx, ry, w, h, isHurt);
  if (enemy.type === 'goblin') drawGoblin(ctx, rx, ry, w, h, isHurt, enemy.direction);
  if (enemy.type === 'knight') {
    ctx.restore();
    drawKnightAnimated(ctx, enemy.levelX, enemy.levelY, w, h, enemy, scrollX);
    if (enemy.state !== 'dead') drawHealthBar(ctx, rx, ry, w, enemy.hp, enemy.maxHp, alpha);
    return;
  }

  ctx.restore();
  if (enemy.state !== 'dead') drawHealthBar(ctx, rx, ry, w, enemy.hp, enemy.maxHp, alpha);
}

function drawSlime(ctx, x, y, w, h, isHurt) {
  // 🦀 Caranguejo — rasteiro e agressivo
  const shell = isHurt ? '#ff4422' : '#c0392b';
  const belly = isHurt ? '#ffaa88' : '#e8886a';
  const dark  = isHurt ? '#991100' : '#6b1a0a';
  const spot  = isHurt ? '#ff7755' : '#a82a10';
  const now   = Date.now();

  // Pernas (3 pares) com animação de caminhada
  ctx.lineWidth = 2.5;
  for (let i = 0; i < 3; i++) {
    const wave = Math.sin(now / 150 + i * 1.2) * 3;
    ctx.strokeStyle = dark;
    // perna esquerda
    const lx = x + w * (0.08 - i * 0.04);
    ctx.beginPath();
    ctx.moveTo(x + w * 0.2, y + h * 0.68);
    ctx.lineTo(lx, y + h * 0.72 + wave);
    ctx.lineTo(lx - 8, y + h * 0.95 + wave);
    ctx.stroke();
    // perna direita
    const rx2 = x + w * (0.92 + i * 0.04);
    ctx.beginPath();
    ctx.moveTo(x + w * 0.8, y + h * 0.68);
    ctx.lineTo(rx2, y + h * 0.72 - wave);
    ctx.lineTo(rx2 + 8, y + h * 0.95 - wave);
    ctx.stroke();
  }

  // Carapaça (oval achatado)
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.ellipse(x+w*.5, y+h*.6, w*.52, h*.44, 0, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = shell;
  ctx.beginPath(); ctx.ellipse(x+w*.5, y+h*.56, w*.48, h*.4, 0, 0, Math.PI*2); ctx.fill();

  // Manchas na carapaça
  ctx.fillStyle = spot;
  ctx.beginPath(); ctx.ellipse(x+w*.35, y+h*.44, w*.09, h*.07, 0.3, 0, Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(x+w*.62, y+h*.42, w*.08, h*.06, -0.2, 0, Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(x+w*.50, y+h*.54, w*.06, h*.05, 0, 0, Math.PI*2); ctx.fill();

  // Barriga
  ctx.fillStyle = belly;
  ctx.beginPath(); ctx.ellipse(x+w*.5, y+h*.73, w*.3, h*.13, 0, 0, Math.PI*2); ctx.fill();

  // Pinças grandes abertas
  const cb = Math.sin(now / 320) * 3;
  // pinça esquerda
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.ellipse(x-w*.16, y+h*.5+cb, w*.22, h*.16, 0.3, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = shell;
  ctx.beginPath(); ctx.ellipse(x-w*.16, y+h*.47+cb, w*.18, h*.13, 0.3, 0, Math.PI*2); ctx.fill();
  // dedo sup esq
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.moveTo(x-w*.05,y+h*.42+cb); ctx.lineTo(x-w*.36,y+h*.28+cb); ctx.lineTo(x-w*.3,y+h*.43+cb); ctx.closePath(); ctx.fill();
  // dedo inf esq
  ctx.beginPath(); ctx.moveTo(x-w*.05,y+h*.56+cb); ctx.lineTo(x-w*.34,y+h*.68+cb); ctx.lineTo(x-w*.26,y+h*.55+cb); ctx.closePath(); ctx.fill();
  // pinça direita
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.ellipse(x+w*1.16, y+h*.5-cb, w*.22, h*.16, -0.3, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = shell;
  ctx.beginPath(); ctx.ellipse(x+w*1.16, y+h*.47-cb, w*.18, h*.13, -0.3, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.moveTo(x+w*1.05,y+h*.42-cb); ctx.lineTo(x+w*1.36,y+h*.28-cb); ctx.lineTo(x+w*1.3,y+h*.43-cb); ctx.closePath(); ctx.fill();
  ctx.beginPath(); ctx.moveTo(x+w*1.05,y+h*.56-cb); ctx.lineTo(x+w*1.34,y+h*.68-cb); ctx.lineTo(x+w*1.26,y+h*.55-cb); ctx.closePath(); ctx.fill();

  // Olhos em palito
  ctx.fillStyle = dark;
  ctx.fillRect(x+w*.3-1, y+h*.12, 3, h*.22);
  ctx.fillRect(x+w*.66-1, y+h*.12, 3, h*.22);
  ctx.fillStyle = isHurt ? '#ffff00' : '#111';
  ctx.beginPath(); ctx.arc(x+w*.3, y+h*.12, 5.5, 0, Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.arc(x+w*.66, y+h*.12, 5.5, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = '#fff';
  ctx.beginPath(); ctx.arc(x+w*.32, y+h*.09, 2, 0, Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.arc(x+w*.68, y+h*.09, 2, 0, Math.PI*2); ctx.fill();
}

function drawGoblin(ctx, x, y, w, h, isHurt, dir) {
  // 🔱 Tritão — guerreiro do mar com tridente
  const skin  = isHurt ? '#ff9966' : '#5bb8a8';
  const dark  = isHurt ? '#cc3300' : '#1a6a60';
  const armor = isHurt ? '#ff6644' : '#2980b9';
  const gold  = isHurt ? '#ffcc44' : '#f0c040';
  const now   = Date.now();
  const bob   = Math.sin(now / 420) * 1.5;

  // Pernas/calda
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.ellipse(x+w*.3, y+h*.88+bob, w*.12, h*.14, 0.2, 0, Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(x+w*.7, y+h*.88+bob, w*.12, h*.14, -0.2, 0, Math.PI*2); ctx.fill();

  // Tronco
  ctx.fillStyle = armor;
  ctx.fillRect(x+w*.2, y+h*.42+bob, w*.6, h*.38);
  // Escamas na armadura
  ctx.fillStyle = dark;
  for (let row = 0; row < 2; row++) {
    for (let col = 0; col < 3; col++) {
      ctx.beginPath();
      ctx.arc(x+w*(0.3+col*.15), y+h*(0.5+row*.12)+bob, 4, Math.PI, Math.PI*2);
      ctx.fill();
    }
  }

  // Cabeça
  ctx.fillStyle = dark;
  ctx.beginPath(); ctx.ellipse(x+w*.5, y+h*.24+bob, w*.24, h*.26, 0, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = skin;
  ctx.beginPath(); ctx.ellipse(x+w*.5, y+h*.22+bob, w*.22, h*.24, 0, 0, Math.PI*2); ctx.fill();

  // Elmo/coroa
  ctx.fillStyle = gold;
  ctx.fillRect(x+w*.28, y+h*.04+bob, w*.44, h*.1);
  // pontas da coroa
  for (let i = 0; i < 3; i++) {
    ctx.beginPath();
    ctx.moveTo(x+w*(0.32+i*.14), y+h*.04+bob);
    ctx.lineTo(x+w*(0.36+i*.14), y-h*.06+bob);
    ctx.lineTo(x+w*(0.40+i*.14), y+h*.04+bob);
    ctx.closePath(); ctx.fill();
  }

  // Olhos
  const ex = dir === 1 ? x+w*.62 : x+w*.38;
  ctx.fillStyle = '#fff';
  ctx.beginPath(); ctx.arc(ex, y+h*.2+bob, 4, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = isHurt ? '#ff0000' : '#001a33';
  ctx.beginPath(); ctx.arc(ex+(dir===1?1:-1), y+h*.2+bob, 2.5, 0, Math.PI*2); ctx.fill();

  // Braços
  ctx.fillStyle = skin;
  ctx.fillRect(x, y+h*.44+bob, w*.22, h*.18);
  ctx.fillRect(x+w*.78, y+h*.44+bob, w*.22, h*.18);

  // TRIDENTE (segurado pelo braço na direção do inimigo)
  const tx = dir === 1 ? x+w*1.05 : x-w*.2;
  const ty = y+h*.3+bob;
  // cabo
  ctx.strokeStyle = '#8B6914'; ctx.lineWidth = 3;
  ctx.beginPath(); ctx.moveTo(tx, ty); ctx.lineTo(tx, ty+h*.6); ctx.stroke();
  // cabeça do tridente
  ctx.strokeStyle = '#c0c0c0'; ctx.lineWidth = 2.5;
  // ponta central
  ctx.beginPath(); ctx.moveTo(tx, ty); ctx.lineTo(tx, ty-h*.18); ctx.stroke();
  // ponta esquerda
  ctx.beginPath(); ctx.moveTo(tx-6, ty); ctx.lineTo(tx-6, ty-h*.13); ctx.stroke();
  // ponta direita
  ctx.beginPath(); ctx.moveTo(tx+6, ty); ctx.lineTo(tx+6, ty-h*.13); ctx.stroke();
  // barra transversal
  ctx.beginPath(); ctx.moveTo(tx-8, ty-h*.06); ctx.lineTo(tx+8, ty-h*.06); ctx.stroke();
  // enfeite de ouro no cabo
  ctx.strokeStyle = gold; ctx.lineWidth = 3;
  ctx.beginPath(); ctx.moveTo(tx-5, ty+h*.14); ctx.lineTo(tx+5, ty+h*.14); ctx.stroke();
}

function drawKnight(ctx, x, y, w, h, isHurt, dir) {
  // 🐙 Polvo — sprite real animado
  if (!polvoImg || !polvoImg.complete) return;

  const now = Date.now();

  // Determine animation row
  let rowName = 'idle';
  // state is passed via enemy object but drawKnight only gets x,y,w,h,isHurt,dir
  // We use isHurt to pick hurt animation; otherwise idle (walk handled below)
  if (isHurt) rowName = 'hurt';

  const frameCount = POLVO_FRAME_COUNTS[rowName];
  const fps = rowName === 'idle' ? 6 : rowName === 'hurt' ? 4 : 8;
  const frame = Math.floor((now / (1000 / fps))) % frameCount;
  const row   = POLVO_ROWS[rowName];

  const sx = frame * POLVO_CELL_W;
  const sy = row   * POLVO_CELL_H;

  // Scale sprite to fit enemy bounding box (keep aspect ratio)
  const scale = Math.min(w / POLVO_CELL_W, h / POLVO_CELL_H) * 2.2;
  const dw = POLVO_CELL_W * scale;
  const dh = POLVO_CELL_H * scale;
  const dx = x + (w - dw) / 2;
  const dy = y + (h - dh) / 2;

  ctx.save();
  if (dir === -1) {
    // Flip horizontally for left-facing direction
    ctx.translate(dx + dw, dy);
    ctx.scale(-1, 1);
    ctx.drawImage(polvoImg, sx, sy, POLVO_CELL_W, POLVO_CELL_H, 0, 0, dw, dh);
  } else {
    ctx.drawImage(polvoImg, sx, sy, POLVO_CELL_W, POLVO_CELL_H, dx, dy, dw, dh);
  }
  ctx.restore();
}

// DrawEnemy com estado completo do inimigo.
function drawKnightAnimated(ctx, x, y, w, h, enemy, scrollX) {
  if (!polvoImg || !polvoImg.complete) return;

  const now = Date.now();
  let rowName;
  if (enemy.state === 'dead')  rowName = 'death';
  else if (enemy.state === 'hurt') rowName = 'hurt';
  else rowName = 'walk';

  const frameCount = POLVO_FRAME_COUNTS[rowName];
  const fpsList = { idle:6, walk:8, slash:10, club:10, hurt:5, death:4 };
  const fps   = fpsList[rowName];
  let frame;
  if (rowName === 'death') {
    // Hold last frame
    const elapsed = enemy.deadTimer || 0;
    frame = Math.min(Math.floor(elapsed / 160), frameCount - 1);
  } else {
    frame = Math.floor((now / (1000 / fps))) % frameCount;
  }

  const row = POLVO_ROWS[rowName];
  const sx  = frame * POLVO_CELL_W;
  const sy  = row   * POLVO_CELL_H;

  const scale = Math.min(w / POLVO_CELL_W, h / POLVO_CELL_H) * 2.2;
  const dw = POLVO_CELL_W * scale;
  const dh = POLVO_CELL_H * scale;
  const rx  = x - scrollX;
  const dx  = rx + (w - dw) / 2;
  const dy  = y + (h - dh) / 2;

  ctx.save();
  if (enemy.direction === -1) {
    ctx.translate(dx + dw, dy);
    ctx.scale(-1, 1);
    ctx.drawImage(polvoImg, sx, sy, POLVO_CELL_W, POLVO_CELL_H, 0, 0, dw, dh);
  } else {
    ctx.drawImage(polvoImg, sx, sy, POLVO_CELL_W, POLVO_CELL_H, dx, dy, dw, dh);
  }
  ctx.restore();
}


function drawHealthBar(ctx, rx, ry, w, hp, maxHp, alpha) {
  const barW = Math.max(w, 32);
  const barH = 5;
  const barX = rx + (w - barW) / 2;
  const barY = ry - 10;
  const ratio = hp / maxHp;
  ctx.save();
  ctx.globalAlpha = alpha;
  ctx.fillStyle = '#1f2937';
  ctx.fillRect(barX, barY, barW, barH);
  ctx.fillStyle = ratio > 0.5 ? '#22c55e' : ratio > 0.25 ? '#f59e0b' : '#ef4444';
  ctx.fillRect(barX, barY, barW * ratio, barH);
  ctx.strokeStyle = '#000'; ctx.lineWidth = 1;
  ctx.strokeRect(barX, barY, barW, barH);
  ctx.restore();
}

// ─── HUD ─────────────────────────────────────────────────────────────────────
function drawHUD(ctx, screenW, lives, maxLives, points, kills, hoverjump) {
  ctx.save();
  ctx.fillStyle = 'rgba(0,0,0,0.45)';
  ctx.fillRect(0, 0, screenW, 40);
  ctx.font = 'bold 18px "Segoe UI",Arial,sans-serif';
  ctx.fillStyle = '#fff';
  ctx.fillText('LIVES:', 35, 26);
  for (let i = 0; i < maxLives; i++) {
    ctx.fillStyle = i < lives ? '#ef4444' : '#6b7280';
    ctx.font = 'bold 20px Arial';
    ctx.fillText(i < lives ? '❤' : '♡', 78 + i * 25, 27);
  }
  if (hoverjump) {
    ctx.fillStyle = '#60a5fa';
    ctx.font = 'bold 14px "Segoe UI",Arial,sans-serif';
    ctx.fillText('⚡ HOVER', 180, 26);
  }
  ctx.font = 'bold 18px "Segoe UI",Arial,sans-serif';
  ctx.fillStyle = '#fbbf24';
  const scoreText = '⭐ ' + String(points).padStart(6, '0');
  const scoreW = ctx.measureText(scoreText).width;
  ctx.fillText(scoreText, screenW - scoreW +40, 26);
  ctx.fillStyle = '#f87171';
  ctx.font = 'bold 14px "Segoe UI",Arial,sans-serif';
  const killText = '☠ ' + kills + ' defeated';
  const killW = ctx.measureText(killText).width;
  ctx.fillText(killText, screenW - killW  +40, 55);
  ctx.restore();
}

function drawHurtOverlay(ctx, screenW, screenH, hurtTimer, hurtDuration) {
  const progress = hurtTimer / hurtDuration;
  if (progress >= 1) return;
  const tick = Math.floor(hurtTimer / 100);
  if (tick % 2 === 1) return;
  const alpha = 0.35 * (1 - progress);
  ctx.save();
  ctx.fillStyle = `rgba(255,0,0,${alpha})`;
  ctx.fillRect(0, 0, screenW, screenH);
  ctx.restore();
}

function drawDamageNumbers(ctx, effects) {
  ctx.save();
  for (const e of effects) {
    const t = e.timer / 800;
    const alpha = 1 - t;
    const floatY = e.y - t * 30;
    ctx.globalAlpha = alpha;
    ctx.font = 'bold 16px "Segoe UI",Arial,sans-serif';
    ctx.fillStyle = '#ffdd22';
    ctx.strokeStyle = '#000'; ctx.lineWidth = 3;
    const rx = e.x - e.scrollX;
    ctx.strokeText(e.text, rx, floatY);
    ctx.fillText(e.text, rx, floatY);
  }
  ctx.restore();
}

// ─── LEVELS / ENEMIES ────────────────────────────────────────────────────────
function floorY(tileRow, h) { return tileRow * TILE_SIZE - h; }

function createEnemies() {
  const make = (type, lx, patrolLeft, patrolRight, tileRow = 14) => {
    const def = ENEMY_DEFS[type];
    return {
      type, levelX: lx, levelY: floorY(tileRow, def.height),
      width: def.width, height: def.height,
      hp: def.maxHp, maxHp: def.maxHp, speed: def.speed,
      direction: 1, state: 'patrol',
      patrolLeft, patrolRight, points: def.points,
      hurtTimer: 0, deadTimer: 0, velocityY: 0,
    };
  };
  return [
    make('slime',  260, 200, 380),
    make('goblin', 420, 340, 530),
    make('slime',  1280, 1220, 1400),
    make('goblin', 1370, 1280, 1420),
    make('knight', 1330, 1250, 1410),
    make('goblin', 1950, 1870, 2080),
    make('slime',  2100, 2010, 2280),
    make('knight', 2200, 2050, 2290),
    make('slime',  850,  835,  885,  11),
    make('goblin', 1045, 1030, 1080, 11),
    make('slime',  1395, 1380, 1435, 11),
    make('goblin', 3100, 3045, 3200),
    make('knight', 3250, 3100, 3400),
    make('slime',  3350, 3200, 3420),
  ];
}

// ─── GAME ENGINE ─────────────────────────────────────────────────────────────
function level0Width(level) { return level[0].length * TILE_SIZE; }

// ===== CLASSE PRINCIPAL DO JOGO =====
class GameEngine {
  constructor(canvas, images, audio) {
    this.ctx    = canvas.getContext('2d');
    this.images = images;
    this.audio  = audio;
    this.audio.volume = 0.5;

    this.pressedKeys       = {};
    this.state             = 'title';
    this.currentLevel      = [];
    this.enemies           = [];
    this.hero              = null;
    this.scrollX           = 0;
    this.points            = 0;
    this.kills             = 0;
    this.hoverjump         = false;
    this.heroAnimIndex     = 1;
    this.heroDir           = 1;
    this.heroJumping       = false;
    this.heroPeakJumping   = false;
    this.jumpPressedLastFrame = false;
    this.newJumpPress      = false;
    this.attackCompleted   = false;
    this.prevAnimIndex     = 1;
    this.resetAnimTime     = Date.now();
    this.distanceFromFloor = 0;
    this.nearestFloorHeight = -59;
    this.audioPlaying      = false;
    this.enterPressedInitially = false;
    this.beyondTitleScreen = false;
    this.oldTime           = Date.now();
    this.frameCounter      = 0;
    this.intervalId        = null;
    this.damageEffects     = [];
    this.attackHitSet      = new Set();
    this.lastAttackIndex   = -1;
    this.projectiles       = [];
    this.pauseMenuOption   = 0;   // 0=continuar, 1=resetar
    this.titleMenuOption   = 0;   // 0=continuar, 1=novo jogo
    this.hasSave           = !!localStorage.getItem('seaAdventureSave');

    this._setupInput();
    this._resetGame();
  }

  _setupInput() {
    window.addEventListener('keydown', e => {
      this.pressedKeys[e.keyCode] = true;
      if (e.keyCode === 13 && !this.enterPressedInitially) {
        this.enterPressedInitially = true;
        this.audio.play().catch(() => {});
      }
    });
    window.addEventListener('keyup', e => { this.pressedKeys[e.keyCode] = false; });
  }

  _resetGame() {
    this.hero = {
      spriteWidth: HERO_SPRITE_WIDTH, spriteHeight: HERO_SPRITE_HEIGHT,
      levelX: 140, levelY: SCREEN_HEIGHT - TILE_SIZE - HERO_SPRITE_HEIGHT,
      renderX: 100, renderY: SCREEN_HEIGHT - TILE_SIZE - HERO_SPRITE_HEIGHT,
      velocityY: 0, lives: MAX_LIVES, hurtTimer: 0, knockbackX: 0,
    };
    this.currentLevel     = JSON.parse(JSON.stringify(LEVEL_DATA[0]));
    this.enemies          = createEnemies();
    this.scrollX          = 0;
    this.points           = 0;
    this.kills            = 0;
    this.hoverjump        = false;
    this.heroAnimIndex    = 1;
    this.heroDir          = 1;
    this.heroJumping      = false;
    this.heroPeakJumping  = false;
    this.jumpPressedLastFrame = false;
    this.newJumpPress     = false;
    this.attackCompleted  = false;
    this.prevAnimIndex    = 1;
    this.resetAnimTime    = Date.now();
    this.distanceFromFloor  = 0;
    this.nearestFloorHeight = -HERO_SPRITE_HEIGHT;
    this.damageEffects    = [];
    this.attackHitSet     = new Set();
    this.lastAttackIndex  = -1;
    this.projectiles      = [];
  }

  start() {
    this.intervalId = setInterval(() => this._tick(Date.now()), INTERVAL * 1000);
  }

  stop() {
    if (this.intervalId !== null) { clearInterval(this.intervalId); this.intervalId = null; }
  }

  _tick(now) {
    this.ctx.clearRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);

    if (this.state !== 'playing' && this.audioPlaying) {
      this.audio.pause();
      this.audioPlaying = false;
    }

    if (this.state === 'title') {
      this._drawTitleScreen(now);
    } else if (this.state === 'paused') {
      // Draw the world as a frozen snapshot then overlay pause menu
      this._drawParallax();
      this._drawTiles();
      for (const enemy of this.enemies) drawEnemy(this.ctx, enemy, this.scrollX);
      this._drawHero(now);
      drawHUD(this.ctx, SCREEN_WIDTH, this.hero.lives, MAX_LIVES, this.points, this.kills, this.hoverjump);
      this._drawPauseMenu(now);
    } else if (this.state === 'gameover') {
      this._drawGameOver(now);
      if (this.pressedKeys[27]) { this._resetGame(); this.state = 'title'; }
    } else if (this.state === 'levelcomplete') {
      this._drawLevelComplete(now);
      if (this.pressedKeys[27]) { this._resetGame(); this.state = 'title'; }
    } else {
      if (!this.audioPlaying) {
        this.audio.currentTime = 0;
        if (this.enterPressedInitially) this.audio.play().catch(() => {});
        this.audioPlaying = true;
      }
      this._gameLoop(now);
    }

    this.frameCounter++;
    if (now - this.oldTime > 1000) { this.frameCounter = 0; this.oldTime = Date.now(); }
  }

  _gameLoop(now) {
    // ESC → pause
    if (this.pressedKeys[27]) {
      this.pressedKeys[27] = false;
      this.state = 'paused';
      this.audio.pause();
      this.audioPlaying = false;
      this.pauseMenuOption = 0;
      return;
    }
    const level = this.currentLevel;

    // Scroll
    const halfW = SCREEN_WIDTH / 2;
    const levelPxW = level[0].length * TILE_SIZE;
    if (
      this.hero.levelX + this.hero.spriteWidth / 2 >= halfW &&
      this.scrollX + SCREEN_WIDTH < levelPxW ||
      (this.hero.levelX + halfW + this.hero.spriteWidth / 2 <= levelPxW && this.scrollX > 0)
    ) {
      this.scrollX = this.hero.levelX - halfW + this.hero.spriteWidth / 2;
    }
    this.hero.renderX = this.hero.levelX - this.scrollX;
    this.hero.renderY = this.hero.levelY;

    // ── RENDER ──────────────────────────────────────────────────────────────
    this._drawParallax();
    this._drawTiles();

    for (const enemy of this.enemies) drawEnemy(this.ctx, enemy, this.scrollX);
    for (const enemy of this.enemies) updateEnemy(enemy, level, INTERVAL);

    // Tritão projéteis — disparo à distância
    this._updateProjectiles();

    const before = this.enemies.length;
    this.enemies = this.enemies.filter(e => !isEnemyRemovable(e));
    this.kills  += before - this.enemies.length;

    const heroHB = {
      levelX: this.hero.levelX + HERO_HITBOX_OFFSET,
      levelY: this.hero.levelY,
      spriteWidth:  HERO_HITBOX_WIDTH,
      spriteHeight: this.hero.spriteHeight,
    };
    const collisions = checkSpriteTileCollisions(heroHB, level);

    this._handleInput(collisions);
    this._applyPhysics(collisions);
    this._drawHero(now);
    this._checkItems();
    this._handleCombat();

    drawHUD(this.ctx, SCREEN_WIDTH, this.hero.lives, MAX_LIVES, this.points, this.kills, this.hoverjump);

    if (this.hero.hurtTimer > 0) {
      drawHurtOverlay(this.ctx, SCREEN_WIDTH, SCREEN_HEIGHT, this.hero.hurtTimer, PLAYER_HURT_DURATION);
      this.hero.hurtTimer = Math.min(this.hero.hurtTimer + INTERVAL * 1000, PLAYER_HURT_DURATION + 100);
    }

    this._updateDamageEffects();
    drawDamageNumbers(this.ctx, this.damageEffects);

    if (this.hero.knockbackX !== 0) {
      this.hero.knockbackX *= 0.8;
      if (Math.abs(this.hero.knockbackX) < 0.5) this.hero.knockbackX = 0;
    }

    if (this.hero.levelY >= SCREEN_HEIGHT) this._loseLife();

    if (this.hero.levelX + this.hero.spriteWidth / 2 >= TILE_SIZE * level[0].length) {
      this.state = 'levelcomplete';
      localStorage.setItem('seaAdventureSave', JSON.stringify({ points: this.points, kills: this.kills, level: 1 }));
      this.audioPlaying = false;
    }

    this.jumpPressedLastFrame = !!this.pressedKeys[87];
    this.prevAnimIndex = this.heroAnimIndex;
  
  }

  _handleInput(collisions) {
    if (this.hero.knockbackX !== 0) {
      const kbDir = this.hero.knockbackX > 0 ? 1 : -1;
      if (!((kbDir === 1 && collisions.right) || (kbDir === -1 && collisions.left))) {
        this.hero.levelX += this.hero.knockbackX;
      }
    }

    if (this.hero.levelX < -HERO_HITBOX_OFFSET) this.hero.levelX = -HERO_HITBOX_OFFSET;
    const maxX = level0Width(this.currentLevel) - this.hero.spriteWidth + HERO_HITBOX_OFFSET + 30;
    if (this.hero.levelX + this.hero.spriteWidth - HERO_HITBOX_OFFSET - 30 > level0Width(this.currentLevel))
      this.hero.levelX = maxX;

    if (this.pressedKeys[65]) {
      if (this.hero.levelX > -HERO_HITBOX_OFFSET && !collisions.left)
        this.hero.levelX -= HERO_MOVE_SPEED * INTERVAL;
      this.heroAnimIndex = 2; this.heroDir = 0;
    }
    if (this.pressedKeys[68]) {
      if (!collisions.right) this.hero.levelX += HERO_MOVE_SPEED * INTERVAL;
      this.heroAnimIndex = 3; this.heroDir = 1;
    }
    if (!this.pressedKeys[65] && !this.pressedKeys[68])
      this.heroAnimIndex = this.heroDir ? 1 : 0;
    if (this.pressedKeys[83])
      this.heroAnimIndex = this.heroDir ? 9 : 8;

    // Attack
    const attacking = !!this.pressedKeys[75];
    const currentFrame = Math.floor(
      ((Date.now() - this.resetAnimTime) / 100) % HERO_ANIMATIONS[this.heroAnimIndex].frames
    );
    if (attacking) {
      if (this.heroDir) {
        if (currentFrame === 4 && this.prevAnimIndex === 7) this.attackCompleted = true;
        if (this.attackCompleted && this.pressedKeys[68]) this.heroAnimIndex = 3;
        else if (this.attackCompleted && !this.pressedKeys[65] && !this.pressedKeys[68]) this.heroAnimIndex = 1;
        else this.heroAnimIndex = 7;
      } else {
        if (currentFrame === 4 && this.prevAnimIndex === 6) this.attackCompleted = true;
        if (this.attackCompleted && this.pressedKeys[65]) this.heroAnimIndex = 2;
        else if (this.attackCompleted && !this.pressedKeys[65] && !this.pressedKeys[68]) this.heroAnimIndex = 0;
        else this.heroAnimIndex = 6;
      }
    } else {
      this.attackCompleted = false;
    }

    // Jump
    if (this.pressedKeys[87]) {
      if (this.distanceFromFloor > 0 || this.hoverjump)
        this.heroAnimIndex = this.heroDir ? 5 : 4;
      this.heroJumping = true;
    } else {
      this.heroJumping = false;
      this.heroPeakJumping = false;
    }

    if (this.prevAnimIndex !== this.heroAnimIndex) this.resetAnimTime = Date.now();
  }

  _applyPhysics(collisions) {
    if (this.hero.velocityY >= 0 && collisions.top) {
      this.nearestFloorHeight = SCREEN_HEIGHT - (collisions.topY ?? 0);
    } else {
      this.nearestFloorHeight = -this.hero.spriteHeight;
    }
    this.distanceFromFloor = SCREEN_HEIGHT - this.nearestFloorHeight - (this.hero.levelY + this.hero.spriteHeight);

    if (this.distanceFromFloor > 0 && !(this.hoverjump && this.heroJumping)) {
      this.hero.velocityY += GRAVITY;
    } else {
      this.hero.velocityY = 0;
    }
    if (this.distanceFromFloor <= 0)
      this.hero.levelY = SCREEN_HEIGHT - this.nearestFloorHeight - this.hero.spriteHeight;

    if (this.hoverjump) {
      const wasPressed = this.heroJumping && !this.newJumpPress;
      this.newJumpPress = wasPressed;
      if (wasPressed) this.hero.velocityY = HOVER_JUMP_VELOCITY;
    } else {
      if (this.heroJumping && !this.newJumpPress && this.distanceFromFloor <= 0 && !this.jumpPressedLastFrame)
        this.newJumpPress = true;
      else this.newJumpPress = false;
      if (this.newJumpPress) { this.hero.levelY -= 1; this.hero.velocityY = JUMP_VELOCITY; }
    }

    if (
      (this.hero.velocityY > 0 && collisions.top) ||
      (this.hero.velocityY < 0 && this.hero.levelY <= -10) ||
      (this.hero.velocityY < 0 && collisions.bottom)
    ) this.hero.velocityY = 0;

    this.hero.levelY += this.hero.velocityY;
  }

  // ===== SISTEMA DE COMBATE =====
_handleCombat() {
    const isAttacking = this.heroAnimIndex === 6 || this.heroAnimIndex === 7;
    if (isAttacking) {
    console.log("ATACANDO", this.heroDir ? "RIGHT" : "LEFT");
    }
    const heroInvincible = this.hero.hurtTimer > 0 && this.hero.hurtTimer < PLAYER_HURT_DURATION;

    if (!isAttacking) { this.attackHitSet.clear(); this.lastAttackIndex = -1; }

    const hbX = this.hero.levelX + HERO_HITBOX_OFFSET;
    const hbY = this.hero.levelY;

    for (const enemy of this.enemies) {
      if (enemy.state === 'dead') continue;

      if (!heroInvincible) {
        const overlap = checkBoxOverlap(
          hbX, hbY, HERO_HITBOX_WIDTH, this.hero.spriteHeight,
          enemy.levelX, enemy.levelY, enemy.width, enemy.height,
        );

        if (overlap) {
          const heroBottom = hbY + this.hero.spriteHeight;
          const enemyTop = enemy.levelY;

          const stomp =
            this.hero.velocityY > 0 &&
            heroBottom < enemyTop + 25;

          if (stomp) {
            hurtEnemy(enemy, 9999);
            this.hero.velocityY = -10;
            this.points += enemy.points;
            continue;
          }

          // ignora colisão quando o jogador está claramente abaixo do inimigo
          if (heroBottom < enemyTop + 18) {
            continue;
          }

          this._loseLife();

          const enemyCX = enemy.levelX + enemy.width / 2;
          const heroCX  = this.hero.levelX + this.hero.spriteWidth / 2;

          this.hero.knockbackX =
            heroCX >= enemyCX ? PLAYER_KNOCKBACK : -PLAYER_KNOCKBACK;
        }
      }

      if (isAttacking && !this.attackHitSet.has(enemy)) {
        const atkX = this.heroDir === 1
        ? hbX + HERO_HITBOX_WIDTH
        : hbX - ATTACK_RANGE_X;

        const atkW = ATTACK_RANGE_X;
        const atkOverlap = checkBoxOverlap(
          atkX, hbY, atkW, this.hero.spriteHeight,
          enemy.levelX, enemy.levelY, enemy.width, enemy.height,
        );
        if (atkOverlap) {
          this.attackHitSet.add(enemy);
          const wasAlive = enemy.hp > 0;
          hurtEnemy(enemy, ATTACK_DAMAGE);
          if (wasAlive && enemy.hp <= 0) this.points += enemy.points;
          this.damageEffects.push({
            x: enemy.levelX + enemy.width / 2, y: enemy.levelY,
            timer: 0, text: `-${ATTACK_DAMAGE}`, scrollX: this.scrollX,
          });
        }
      }
    }
  }

  _updateProjectiles() {
    const hero    = this.hero;
    const heroInv = hero.hurtTimer > 0 && hero.hurtTimer < PLAYER_HURT_DURATION;
    const hbX = hero.levelX + HERO_HITBOX_OFFSET;
    const hbY = hero.levelY;

    // Spawn tridentes de goblin próximos ao herói
    for (const enemy of this.enemies) {
      if (enemy.type !== 'goblin' || enemy.state !== 'patrol') continue;
      if (!enemy.shootCooldown || enemy.shootCooldown <= 0) {
        const dist = Math.abs((enemy.levelX + enemy.width/2) - (hero.levelX + hero.spriteWidth/2));
        if (dist < 320 && dist > 60) {
          this.projectiles.push(createTrident(enemy));
          enemy.shootCooldown = 2400 + Math.random() * 800;
        } else {
          enemy.shootCooldown = 600;
        }
      }
    }

    // Mover e checar projéteis
    for (const p of this.projectiles) {
      p.timer += INTERVAL * 1000;
      p.levelX += p.vx * INTERVAL;

      // Hit no herói
      if (!heroInv && checkBoxOverlap(p.levelX, p.levelY, p.width, p.height, hbX, hbY, HERO_HITBOX_WIDTH, hero.spriteHeight)) {
        p.timer = p.lifetime + 1;
        this._loseLife();
        const enemyCX = p.levelX + p.width/2;
        const heroCX  = hero.levelX + hero.spriteWidth/2;
        hero.knockbackX = heroCX >= enemyCX ? PLAYER_KNOCKBACK : -PLAYER_KNOCKBACK;
      }
    }

    // Desenhar tridentes
    for (const p of this.projectiles) {
      if (p.timer >= p.lifetime) continue;
      const rx = p.levelX - this.scrollX;
      const ry = p.levelY;
      const spin = (p.timer / 120) * Math.PI * 2 * p.dir;
      this.ctx.save();
      this.ctx.translate(rx + p.width/2, ry + p.height/2);
      this.ctx.rotate(spin);
      // Cabo
      this.ctx.strokeStyle = '#8B6914'; this.ctx.lineWidth = 3;
      this.ctx.beginPath(); this.ctx.moveTo(-10, 0); this.ctx.lineTo(10, 0); this.ctx.stroke();
      // Ponta
      this.ctx.strokeStyle = '#c0c0c0'; this.ctx.lineWidth = 2;
      this.ctx.beginPath(); this.ctx.moveTo(8, 0); this.ctx.lineTo(14, 0); this.ctx.stroke();
      this.ctx.beginPath(); this.ctx.moveTo(6, -4); this.ctx.lineTo(12, -4); this.ctx.stroke();
      this.ctx.beginPath(); this.ctx.moveTo(6, 4); this.ctx.lineTo(12, 4); this.ctx.stroke();
      this.ctx.beginPath(); this.ctx.moveTo(7, -5); this.ctx.lineTo(7, 5); this.ctx.stroke();
      // Brilho
      this.ctx.strokeStyle = 'rgba(255,255,180,0.6)'; this.ctx.lineWidth = 1;
      this.ctx.beginPath(); this.ctx.moveTo(-8, -2); this.ctx.lineTo(6, -2); this.ctx.stroke();
      this.ctx.restore();
    }

    // Limpar projéteis expirados
    this.projectiles = this.projectiles.filter(p => p.timer < p.lifetime);
  }

  _loseLife() {
    this.hero.lives--;
    this.hero.hurtTimer = 1;
    if (this.hero.lives <= 0) { this.state = 'gameover'; this.audioPlaying = false; localStorage.removeItem('seaAdventureSave'); }
    this.hero.levelY    = SCREEN_HEIGHT - TILE_SIZE - HERO_SPRITE_HEIGHT;
    this.hero.velocityY = 0;
  }

  _checkItems() {
    // Wings at tile col 82, row 13
    const wingCol = 82, wingRow = 13;
    const wc = { top: false, bottom: false, left: false, right: false, topY: null };
    checkSpriteTileCollision(
      { levelX: this.hero.levelX + 25, levelY: this.hero.levelY, spriteWidth: 50, spriteHeight: this.hero.spriteHeight },
      wingCol * TILE_SIZE, wingRow * TILE_SIZE, wc,
    );
    if (wc.top || wc.bottom || wc.left || wc.right) {
      if (this.currentLevel[wingRow][wingCol] === 10) {
        this.points += 800;
        this.currentLevel[wingRow][wingCol] = 0;
      }
      this.hoverjump = true;
    }

    // Golden Cross at tile col 102, row 2
    const crossCol = 102, crossRow = 2;
    const cc = { top: false, bottom: false, left: false, right: false, topY: null };
    checkSpriteTileCollision(
      { levelX: this.hero.levelX + 25, levelY: this.hero.levelY, spriteWidth: 50, spriteHeight: this.hero.spriteHeight },
      crossCol * TILE_SIZE, crossRow * TILE_SIZE, cc,
    );
    if (cc.top || cc.bottom || cc.left || cc.right) {
      if (this.currentLevel[crossRow][crossCol] === 12) {
        this.points += 10000;
        this.currentLevel[crossRow][crossCol] = 0;
      }
    }
  }

  _updateDamageEffects() {
    for (const e of this.damageEffects) e.timer += INTERVAL * 1000;
    this.damageEffects = this.damageEffects.filter(e => e.timer < 800);
  }

  // ─── DRAWING ───────────────────────────────────────────────────────────────
  _drawParallax() {
    const layers = [
      this.images.parallaxBg,
      this.images.parallaxMountainFar,
      this.images.parallaxMountains,
      this.images.parallaxTrees,
      this.images.parallaxFgTrees,
    ];
    for (let i = 0; i < layers.length; i++) {
      if (i === 0) {
        this.ctx.drawImage(layers[i], 0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
      } else {
        let sx = 0.005 * this.scrollX * Math.pow(2, i);
        if (i === 4) sx -= Math.floor(sx / 263) * 263;
        else         sx -= Math.floor(sx / 272) * 272;
        this.ctx.drawImage(layers[i], sx, 0, 272, 160, 0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
      }
    }
  }

  _drawTiles() {
    const level  = this.currentLevel;
    const hTiles = level[0].length;
    const vTiles = level.length;
    for (let i = 0; i < hTiles; i++) {
      for (let j = 0; j < vTiles; j++) {
        const t = level[j][i];
        if      (t === 1)  this._drawTile(32*i - this.scrollX, j*32, 18 + 64*3);
        else if (t === 10) this._drawTile(32*i - this.scrollX, j*32, 49 + 64*9);
        else if (t === 12) this._drawTile(32*i - this.scrollX, j*32, 23 + 64*1);
        else if (t !== 0)  this._drawTile(32*i - this.scrollX, j*32, (41+t) + 64*6);
      }
    }
  }

  _drawTile(x, y, tileIndex) {
    const sx = (tileIndex * 32) - (64 * Math.floor(tileIndex / 64) * 32);
    const sy = Math.floor(tileIndex / 64) * 32;
    this.ctx.drawImage(this.images.tiles, sx, sy, 32, 32, x, y, 32, 32);
  }

  _drawHero(now) {
    const anim = HERO_ANIMATIONS[this.heroAnimIndex];
    let currentFrame = Math.floor(((Date.now() - this.resetAnimTime) / 100) % anim.frames);
    if ((this.heroAnimIndex === 4 || this.heroAnimIndex === 5) && this.heroJumping && currentFrame === anim.frames - 1)
      this.heroPeakJumping = true;
    if ((this.heroAnimIndex === 4 || this.heroAnimIndex === 5) && this.heroPeakJumping)
      currentFrame = anim.frames - 1;
    const reverseFrames = [0, 2, 4];

  if (
      this.heroDir === 0 &&
      reverseFrames.includes(this.heroAnimIndex)
  ) {
      currentFrame = anim.frames - currentFrame - 1;
  }

    const img = this.images[anim.key];
    this.ctx.drawImage(
      img, currentFrame * HERO_SPRITE_WIDTH, 0, HERO_SPRITE_WIDTH, HERO_SPRITE_HEIGHT,
      this.hero.renderX, this.hero.renderY, HERO_SPRITE_WIDTH, HERO_SPRITE_HEIGHT,
    );
  }

  _drawTitleScreen(now) {
    const ctx = this.ctx;
    const W = SCREEN_WIDTH, H = SCREEN_HEIGHT;
    const t = Date.now();

    ctx.drawImage(this.images.titleScreen, 0, 0, 384, 224, 0, 0, W, H);

    // Título
    ctx.textAlign = 'center';
    ctx.font = '90px Luminari, fantasy';
    ctx.fillStyle = 'rgb(224, 188, 41)';
    ctx.shadowColor = 'rgba(39, 17, 2, 0.6)';
    ctx.shadowBlur = 18;
    ctx.fillText('Sea Adventure', W/2, 130);
    ctx.shadowBlur = 0;

    // Sprite do herói animado
    const anim = HERO_ANIMATIONS[this.heroAnimIndex];
    const cf   = Math.floor((t / 100) % anim.frames);
    const img  = this.images[anim.key];
    ctx.drawImage(img, cf * HERO_SPRITE_WIDTH, 0, HERO_SPRITE_WIDTH, HERO_SPRITE_HEIGHT,
      W/2 - 100, 160, 200, 118);

    // ── Menu buttons ────────────────────────────────────────────────────────
    const options = this.hasSave
      ? ['Continuar Jogando', 'Novo Jogo']
      : ['Novo Jogo'];

    // Handle input
    if (this.pressedKeys[38] || this.pressedKeys[87]) { // up / W
      this.pressedKeys[38] = this.pressedKeys[87] = false;
      this.titleMenuOption = (this.titleMenuOption - 1 + options.length) % options.length;
    }
    if (this.pressedKeys[40] || this.pressedKeys[83]) { // down / S
      this.pressedKeys[40] = this.pressedKeys[83] = false;
      this.titleMenuOption = (this.titleMenuOption + 1) % options.length;
    }
    if (this.pressedKeys[13] || this.pressedKeys[32]) { // Enter or Space
      this.pressedKeys[13] = this.pressedKeys[32] = false;
      this.beyondTitleScreen = true;
      if (!this.hasSave || this.titleMenuOption === (this.hasSave ? 1 : 0)) {
        // Novo Jogo
        localStorage.removeItem('seaAdventureSave');
        this.hasSave = false;
        this._resetGame();
      } else {
        // Continuar — restore save
        const save = JSON.parse(localStorage.getItem('seaAdventureSave') || '{}');
        this._resetGame();
        if (save.points) this.points = save.points;
        if (save.kills)  this.kills  = save.kills;
      }
      this.state = 'playing';
      return;
    }

    // Draw menu panel
    const panW = 320, panH = options.length * 60 + 24;
    const panX = W/2 - panW/2, panY = 300;
    ctx.fillStyle = 'rgba(0,10,30,0.72)';
    this._roundRect(ctx, panX, panY, panW, panH, 12);
    ctx.fill();
    ctx.strokeStyle = 'rgba(212, 220, 60, 0.4)';
    ctx.lineWidth = 1.5;
    this._roundRect(ctx, panX, panY, panW, panH, 12);
    ctx.stroke();

    options.forEach((label, i) => {
      const sel = i === this.titleMenuOption;
      const btnY = panY + 18 + i * 60;

      if (sel) {
        ctx.fillStyle = 'rgba(38, 94, 173, 0.35)';
        this._roundRect(ctx, panX + 10, btnY, panW - 20, 48, 8);
        ctx.fill();
        ctx.strokeStyle = 'rgba(100,180,255,0.7)';
        ctx.lineWidth = 1.5;
        this._roundRect(ctx, panX + 10, btnY, panW - 20, 48, 8);
        ctx.stroke();
      }

      const pulse = sel ? (0.85 + 0.15 * Math.cos(2 * Math.PI * (t % 800) / 800)) : 0.65;
      ctx.globalAlpha = pulse;
      ctx.font = sel ? 'bold 28px Digivolve' : '26px Digivolve';
      ctx.fillStyle = sel ? '#7dd3fc' : '#94a3b8';
      ctx.shadowColor = sel ? 'rgba(100,180,255,0.8)' : 'none';
      ctx.shadowBlur  = sel ? 10 : 0;
      ctx.textAlign = 'center';
      ctx.fillText((sel ? '▶ ' : '   ') + label, W/2, btnY + 31);
      ctx.globalAlpha = 1;
      ctx.shadowBlur = 0;
    });

    // Dica de controles
    ctx.font = '16px Luminari, fantasy';
    ctx.fillStyle = 'rgba(255,247,200,0.6)';
    ctx.textAlign = 'center';
    ctx.fillText('↑↓ Navegar  |  Enter Confirmar', W/2, panY + panH + 28);
    ctx.fillText('WASD: Mover/Pular  |  K: Atacar  |  S: Abaixar', W/2, panY + panH + 50);
    ctx.textAlign = 'left';
  }

  _drawPauseMenu(now) {
    const ctx = this.ctx;
    const W = SCREEN_WIDTH, H = SCREEN_HEIGHT;
    const t = Date.now();

    // Overlay escuro semitransparente
    ctx.fillStyle = 'rgba(0,8,30,0.72)';
    ctx.fillRect(0, 0, W, H);

    // Brilho central
    const glow = ctx.createRadialGradient(W/2, H/2, 0, W/2, H/2, 280);
    glow.addColorStop(0, 'rgba(10,40,100,0.25)');
    glow.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, W, H);

    // Painel principal
    const panW = 340, panH = 220;
    const panX = W/2 - panW/2, panY = H/2 - panH/2;
    ctx.fillStyle = 'rgba(4,12,40,0.92)';
    this._roundRect(ctx, panX, panY, panW, panH, 14);
    ctx.fill();
    const border = ctx.createLinearGradient(panX, panY, panX+panW, panY+panH);
    border.addColorStop(0,   'rgba(40,120,220,0.5)');
    border.addColorStop(0.5, 'rgba(100,180,255,0.8)');
    border.addColorStop(1,   'rgba(40,120,220,0.5)');
    ctx.strokeStyle = border;
    ctx.lineWidth = 1.8;
    this._roundRect(ctx, panX, panY, panW, panH, 14);
    ctx.stroke();

    // Título PAUSADO
    ctx.textAlign = 'center';
    ctx.shadowColor = 'rgba(119, 71, 19, 0.7)';
    ctx.shadowBlur  = 16;
    ctx.font = 'bold 42px Luminari, fantasy';
    ctx.fillStyle = '#d0b943';
    ctx.fillText('PAUSADO', W/2, panY + 54);
    ctx.shadowBlur = 0;

    // Linha divisória
    const lineG = ctx.createLinearGradient(panX+20, 0, panX+panW-20, 0);
    lineG.addColorStop(0, 'rgba(60,140,220,0)');
    lineG.addColorStop(0.5, 'rgba(60,140,220,0.6)');
    lineG.addColorStop(1, 'rgba(60,140,220,0)');
    ctx.strokeStyle = lineG; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(panX+20, panY+66); ctx.lineTo(panX+panW-20, panY+66); ctx.stroke();

    // Opções
    const options = ['Continuar', 'Resetar Fase'];

    // Input handling
    if (this.pressedKeys[38] || this.pressedKeys[87]) {
      this.pressedKeys[38] = this.pressedKeys[87] = false;
      this.pauseMenuOption = (this.pauseMenuOption - 1 + options.length) % options.length;
    }
    if (this.pressedKeys[40] || this.pressedKeys[83]) {
      this.pressedKeys[40] = this.pressedKeys[83] = false;
      this.pauseMenuOption = (this.pauseMenuOption + 1) % options.length;
    }
    if (this.pressedKeys[13] || this.pressedKeys[32] || this.pressedKeys[27]) {
      const chosen = this.pressedKeys[27] ? 0 : this.pauseMenuOption; // ESC sempre continua
      this.pressedKeys[13] = this.pressedKeys[32] = this.pressedKeys[27] = false;
      if (chosen === 0) {
        // Continuar
        this.state = 'playing';
        this.lastTime = Date.now();
      } else {
        // Resetar fase
        localStorage.removeItem('seaAdventureSave');
        this.hasSave = false;
        this._resetGame();
        this.state = 'playing';
      }
      return;
    }

    options.forEach((label, i) => {
      const sel = i === this.pauseMenuOption;
      const btnY = panY + 82 + i * 58;

      if (sel) {
        ctx.fillStyle = 'rgba(188, 186, 32, 0.38)';
        this._roundRect(ctx, panX + 14, btnY, panW - 28, 46, 8);
        ctx.fill();
        ctx.strokeStyle = 'rgba(100,180,255,0.65)';
        ctx.lineWidth = 1.3;
        this._roundRect(ctx, panX + 14, btnY, panW - 28, 46, 8);
        ctx.stroke();
      }

      const pulse = sel ? (0.88 + 0.12 * Math.cos(2 * Math.PI * (t % 700) / 700)) : 0.7;
      ctx.globalAlpha = pulse;
      ctx.font = sel ? 'bold 26px Digivolve' : '24px Digivolve';
      ctx.fillStyle = sel ? '#dcef09' : '#a2c50a';
      ctx.shadowColor = sel ? 'rgba(31, 6, 2, 0.8)' : 'none';
      ctx.shadowBlur  = sel ? 8 : 0;
      ctx.textAlign = 'center';
      ctx.fillText((sel ? '▶ ' : '   ') + label, W/2, btnY + 30);
      ctx.globalAlpha = 1;
      ctx.shadowBlur = 0;
    });

    // Dica ESC
    ctx.font = '14px Digivolve, fantasy';
    ctx.fillStyle = 'rgba(153, 185, 56, 0.55)';
    ctx.textAlign = 'center';
    ctx.fillText('ESC para continuar', W/2, panY + panH - 12);
    ctx.textAlign = 'left';
  }

  _drawGameOver(now) {
    const ctx = this.ctx;
    const W = SCREEN_WIDTH, H = SCREEN_HEIGHT;
    const t = Date.now();

    // ── Fundo preto com vinheta vermelha ──────────────────────────────────────
    ctx.fillStyle = '#060006';
    ctx.fillRect(0, 0, W, H);

    // Vinheta sangrenta nas bordas
    const vign = ctx.createRadialGradient(W/2, H/2, H*0.2, W/2, H/2, H*0.85);
    vign.addColorStop(0, 'rgba(0,0,0,0)');
    vign.addColorStop(1, 'rgba(80,0,0,0.85)');
    ctx.fillStyle = vign;
    ctx.fillRect(0, 0, W, H);

    // Brilho central sutil
    const glow = ctx.createRadialGradient(W/2, H/2, 0, W/2, H/2, 300);
    glow.addColorStop(0, 'rgba(120,0,0,0.18)');
    glow.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, W, H);

    // ── Partículas de brasa caindo ─────────────────────────────────────────────
    if (!this._goParticles) {
      this._goParticles = Array.from({length: 35}, () => ({
        x: Math.random() * W,
        y: Math.random() * H,
        vy: 0.3 + Math.random() * 0.8,
        vx: (Math.random() - 0.5) * 0.4,
        r: 1 + Math.random() * 2.5,
        life: Math.random(),
        col: ['#ff2200','#ff4400','#cc0000','#ff6600','#ff1100'][Math.floor(Math.random()*5)]
      }));
    }
    this._goParticles.forEach(p => {
      p.y += p.vy; p.x += p.vx; p.life += 0.008;
      if (p.y > H + 5) { p.y = -5; p.x = Math.random() * W; p.life = 0; }
      const a = 0.15 + 0.65 * Math.sin(p.life * Math.PI);
      ctx.globalAlpha = a;
      ctx.fillStyle = p.col;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1;

    // ── Linha divisória superior ───────────────────────────────────────────────
    const lineGrad = ctx.createLinearGradient(0, 0, W, 0);
    lineGrad.addColorStop(0,   'rgba(180,0,0,0)');
    lineGrad.addColorStop(0.5, 'rgba(220,0,0,0.9)');
    lineGrad.addColorStop(1,   'rgba(180,0,0,0)');
    ctx.strokeStyle = lineGrad;
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(80, 68); ctx.lineTo(W - 80, 68); ctx.stroke();

    // ── Título GAME OVER com efeito flicker ───────────────────────────────────
    const flicker = (Math.sin(t * 0.003) > 0.97 || Math.sin(t * 0.007) > 0.98)
      ? 0.6 + Math.random() * 0.4
      : 1.0;
    ctx.globalAlpha = flicker;

    ctx.shadowColor = '#ff0000';
    ctx.shadowBlur  = 30 + 12 * Math.sin(t * 0.003);
    ctx.font = 'bold 84px Luminari, fantasy';
    ctx.textAlign = 'center';

    // Sombra deslocada
    ctx.fillStyle = '#3a0000';
    ctx.fillText('Game Over', W/2 + 4, 140);
    // Texto principal
    ctx.fillStyle = '#cc1111';
    ctx.fillText('Game Over', W/2, 136);

    ctx.shadowBlur = 0;
    ctx.globalAlpha = 1;

    // ── Linha divisória inferior ao título ────────────────────────────────────
    ctx.strokeStyle = lineGrad;
    ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(120, 158); ctx.lineTo(W - 120, 158); ctx.stroke();

    // ── Painel de stats ───────────────────────────────────────────────────────
    const panX = W/2 - 220, panY = 172, panW = 440, panH = 110;
    ctx.fillStyle = 'rgba(60,0,0,0.45)';
    this._roundRect(ctx, panX, panY, panW, panH, 8);
    ctx.fill();
    ctx.strokeStyle = 'rgba(180,0,0,0.4)';
    ctx.lineWidth = 1;
    this._roundRect(ctx, panX, panY, panW, panH, 8);
    ctx.stroke();

    // Divisor vertical do painel
    ctx.strokeStyle = 'rgba(180,0,0,0.25)';
    ctx.beginPath(); ctx.moveTo(W/2, panY + 14); ctx.lineTo(W/2, panY + panH - 14); ctx.stroke();

    // Stat: Pontuação
    ctx.textAlign = 'center';
    ctx.font = 'bold 11px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#662222';
    ctx.fillText('PONTUAÇÃO', W/2 - 110, panY + 28);
    ctx.font = 'bold 28px Luminari, fantasy';
    ctx.fillStyle = '#ffaa33';
    ctx.fillText(String(this.points).padStart(6,'0'), W/2 - 110, panY + 68);
    ctx.font = '10px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#664422';
    ctx.fillText('pts', W/2 - 110, panY + 88);

    // Stat: Abates
    ctx.font = 'bold 11px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#662222';
    ctx.fillText('ABATES', W/2 + 110, panY + 28);
    ctx.font = 'bold 42px Luminari, fantasy';
    ctx.fillStyle = '#ff4444';
    ctx.fillText(this.kills, W/2 + 110, panY + 72);

    // ── Linha "Press ESC" piscante ─────────────────────────────────────────────
    const escAlpha = 0.45 + 0.45 * Math.cos(2 * Math.PI * (t % 1200) / 1200);
    ctx.globalAlpha = escAlpha;
    ctx.font = '26px Luminari, fantasy';
    ctx.fillStyle = '#ffeecc';
    ctx.fillText('Press ESC to Exit', W/2, 338);
    ctx.globalAlpha = 1;

    // ── Sprite do herói (hurt) ────────────────────────────────────────────────
    const anim = HERO_ANIMATIONS[11];
    const cf   = Math.floor((t / 120) % anim.frames);
    const img  = this.images[anim.key];
    const sw = 200, sh = 118;
    ctx.drawImage(img, cf * HERO_SPRITE_WIDTH, 0, HERO_SPRITE_WIDTH, HERO_SPRITE_HEIGHT,
      W/2 - sw/2, 360, sw, sh);

    ctx.textAlign = 'left';
    ctx.shadowBlur = 0;
  }

  _roundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  _drawLevelComplete(now) {
    const ctx = this.ctx;
    const W = SCREEN_WIDTH, H = SCREEN_HEIGHT;
    const t = Date.now();

    // ── Background (usa imagem se disponível, senão gradiente) ─────────────────
    if (levelCompleteBg.complete && levelCompleteBg.naturalWidth > 0) {
      ctx.drawImage(levelCompleteBg, 0, 0, W, H);
    } else {
      ctx.fillStyle = 'rgb(12,12,28)';
      ctx.fillRect(0, 0, W, H);
    }

    // Overlay escuro semitransparente
    ctx.fillStyle = 'rgba(0,0,0,0.52)';
    ctx.fillRect(0, 0, W, H);

    // ── Confetes/partículas douradas ──────────────────────────────────────────
    if (!this._lcParticles) {
      const cols = ['#4ade80','#fbbf24','#f87171','#60a5fa','#a78bfa','#34d399'];
      this._lcParticles = Array.from({length: 40}, (_, i) => ({
        x: Math.random() * W,
        y: Math.random() * H,
        vy: 0.5 + Math.random() * 1.2,
        vx: (Math.random() - 0.5) * 0.6,
        r: 2 + Math.random() * 3,
        col: cols[i % cols.length],
        rot: Math.random() * Math.PI * 2,
        life: Math.random()
      }));
    }
    this._lcParticles.forEach(p => {
      p.y += p.vy; p.x += p.vx; p.rot += 0.05; p.life += 0.006;
      if (p.y > H + 8) { p.y = -8; p.x = Math.random() * W; p.life = 0; }
      const a = 0.2 + 0.7 * Math.sin(p.life * Math.PI);
      ctx.globalAlpha = a;
      ctx.fillStyle = p.col;
      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rot);
      ctx.fillRect(-p.r/2, -p.r/2, p.r, p.r * 1.6);
      ctx.restore();
    });
    ctx.globalAlpha = 1;

    // ── Linhas douradas divisórias ─────────────────────────────────────────────
    const gold = ctx.createLinearGradient(0, 0, W, 0);
    gold.addColorStop(0,   'rgba(240,192,64,0)');
    gold.addColorStop(0.5, 'rgba(240,192,64,0.85)');
    gold.addColorStop(1,   'rgba(240,192,64,0)');
    ctx.strokeStyle = gold;
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(60, 66); ctx.lineTo(W - 60, 66); ctx.stroke();

    // ── Badge de fase ──────────────────────────────────────────────────────────
    ctx.textAlign = 'center';
    ctx.font = 'bold 11px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = 'rgba(240,192,64,0.7)';
    ctx.letterSpacing = '3px';
    ctx.fillText('— FASE 1 COMPLETA —', W/2, 54);

    // ── Título Level Complete! ─────────────────────────────────────────────────
    ctx.shadowColor = '#4ade8088';
    ctx.shadowBlur  = 20 + 8 * Math.sin(t * 0.003);
    ctx.font = 'bold 80px Luminari, fantasy';
    // Sombra
    ctx.fillStyle = '#1a4a22';
    ctx.fillText('Level Complete!', W/2 + 3, 143);
    // Texto principal
    ctx.fillStyle = '#4ade80';
    ctx.fillText('Level Complete!', W/2, 140);
    ctx.shadowBlur = 0;

    // ── Estrelas animadas ──────────────────────────────────────────────────────
    const starCx = W/2;
    const starY  = 170;
    const starGap = 52;
    for (let i = 0; i < 3; i++) {
      const delay = i * 300;
      const pop   = Math.min(1, Math.max(0, (t % 3000 - delay) / 250));
      const scale = pop < 1 ? pop * 1.3 : 1 + 0.04 * Math.sin(t * 0.004 + i);
      ctx.save();
      ctx.translate(starCx + (i - 1) * starGap, starY);
      ctx.scale(scale, scale);
      ctx.font = '32px serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.shadowColor = '#fbbf24';
      ctx.shadowBlur = 12;
      ctx.fillText('⭐', 0, 0);
      ctx.restore();
    }
    ctx.shadowBlur = 0;
    ctx.textBaseline = 'alphabetic';

    // ── Linha divisória ────────────────────────────────────────────────────────
    ctx.strokeStyle = gold;
    ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(100, 200); ctx.lineTo(W - 100, 200); ctx.stroke();

    // ── Painel de stats ───────────────────────────────────────────────────────
    const panX = W/2 - 240, panY = 210, panW = 480, panH = 118;
    ctx.fillStyle = 'rgba(0,20,10,0.55)';
    this._roundRect(ctx, panX, panY, panW, panH, 8);
    ctx.fill();
    ctx.strokeStyle = 'rgba(74,222,128,0.2)';
    ctx.lineWidth = 1;
    this._roundRect(ctx, panX, panY, panW, panH, 8);
    ctx.stroke();

    // Divisor central
    ctx.strokeStyle = 'rgba(74,222,128,0.15)';
    ctx.beginPath(); ctx.moveTo(W/2, panY + 14); ctx.lineTo(W/2, panY + panH - 14); ctx.stroke();

    // Stat: Pontuação
    ctx.textAlign = 'center';
    ctx.font = 'bold 11px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#2a6640';
    ctx.fillText('PONTUAÇÃO', W/2 - 120, panY + 28);
    ctx.font = 'bold 30px Luminari, fantasy';
    ctx.fillStyle = '#fbbf24';
    ctx.fillText(String(this.points).padStart(6,'0'), W/2 - 120, panY + 72);
    ctx.font = '10px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#2a5030';
    ctx.fillText('pts', W/2 - 120, panY + 92);

    // Stat: Inimigos derrotados
    ctx.font = 'bold 11px "Segoe UI", Arial, sans-serif';
    ctx.fillStyle = '#2a6640';
    ctx.fillText('INIMIGOS DERROTADOS', W/2 + 120, panY + 28);
    ctx.font = 'bold 40px Luminari, fantasy';
    ctx.fillStyle = '#f87171';
    ctx.fillText(this.kills, W/2 + 120, panY + 76);

    // ── Press ESC piscante ─────────────────────────────────────────────────────
    const escA = 0.45 + 0.45 * Math.cos(2 * Math.PI * (t % 1200) / 1200);
    ctx.globalAlpha = escA;
    ctx.font = '26px Luminari, fantasy';
    ctx.fillStyle = '#d4e8cc';
    ctx.fillText('Press ESC for Title', W/2, 356);
    ctx.globalAlpha = 1;

    // ── Sprite do herói (idle) ────────────────────────────────────────────────
    const anim = HERO_ANIMATIONS[1];
    const cf   = Math.floor((t / 120) % anim.frames);
    const img  = this.images[anim.key];
    const sw = 200, sh = 118;
    ctx.drawImage(img, cf * HERO_SPRITE_WIDTH, 0, HERO_SPRITE_WIDTH, HERO_SPRITE_HEIGHT,
      W/2 - sw/2, 368, sw, sh);

    ctx.textAlign = 'left';
    ctx.shadowBlur = 0;
  }
}


// Background da tela de fase concluída
const levelCompleteBg = new Image();
levelCompleteBg.src = 'assets/level-complete-bg.png';

// ─── BOOTSTRAP ───────────────────────────────────────────────────────────────
function loadImage(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload  = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });
}

